Here's a simple C++ function that converts markdown text to html:

```cpp
#include <iostream>
#include <string>

std::string markdown_to_html(const std::string& markdown) {
    // Replace newlines with <br>
    std::string html = std::replace(markdown.begin(), markdown.end(), '\n', "<br>");

    // Replace asterisks and underscores for emphasis
    html = std::replace(html.begin(), html.end(), '*', "<em>");
    html = std::replace(html.begin(), html.end(), '_', "</em>");

    return html;
}

int main() {
    std::string markdown = "# Hello World\n\n*This is a list item*";
    std::string html = markdown_to_html(markdown);
    std::cout << html << "\n";
    return 0;
}
```

This function currently only supports simple markdown syntax (headers and lists). For more complex markdown formatting, you might need to use a library or a more advanced implementation.

